-- Converted from docs/du_lieu_daNhap.sql table QLTB_LOC.WTB_00_HO_SO_THIET_BI_CHI_TET.
-- Imports equipment parameter definitions and per-device parameter values.
-- Audit for real detail values follows old LOG_USER/LOG_DATE; generated unit catalog rows use migration user 0044.
SET NOCOUNT ON;
SET XACT_ABORT ON;
BEGIN TRANSACTION;

DECLARE @MaNguoiNhapMigration NVARCHAR(50) = N'0044';
DECLARE @TenNguoiNhapMigration NVARCHAR(250) = N'Trương Văn Voôn';

IF OBJECT_ID('tempdb..#DonViTinhChiTiet') IS NOT NULL DROP TABLE #DonViTinhChiTiet;
CREATE TABLE #DonViTinhChiTiet (Ma NVARCHAR(50) NOT NULL, Ten NVARCHAR(250) NOT NULL);

MERGE dbo.DmDungChung AS target
USING #DonViTinhChiTiet AS source
ON target.NhomDanhMuc = N'DON_VI_TINH' AND target.Ten = source.Ten
WHEN NOT MATCHED BY TARGET THEN
    INSERT (Id, NhomDanhMuc, Ma, Ten, GhiChu, SapXep, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), N'DON_VI_TINH', source.Ma, source.Ten, N'Đơn vị tính phát sinh từ WTB_00_HO_SO_THIET_BI_CHI_TET', NULL, 1, SYSDATETIME(), @MaNguoiNhapMigration, @TenNguoiNhapMigration);

IF OBJECT_ID('tempdb..#ThongSoCu') IS NOT NULL DROP TABLE #ThongSoCu;
CREATE TABLE #ThongSoCu (
    IdChiTiet NVARCHAR(50) NOT NULL, MaThietBi NVARCHAR(50) NOT NULL, MaThongSo NVARCHAR(50) NOT NULL, TenThongSo NVARCHAR(250) NOT NULL,
    GiaTriNumber DECIMAL(18,4) NULL, TenDonViTinh NVARCHAR(250) NULL, GhiChu NVARCHAR(500) NULL,
    LogDate DATETIME2 NULL, LogUser NVARCHAR(50) NULL, LogDateLast DATETIME2 NULL, LogUserLast NVARCHAR(50) NULL, IdHstb NVARCHAR(50) NULL
);

;WITH DmSourceRaw AS (
    SELECT
        tb.NhomThietBiId, c.MaThongSo, c.TenThongSo, dvt.Id AS DonViTinhId, c.GhiChu,
        ISNULL(c.LogDate, SYSDATETIME()) AS NgayKhoiTao, c.LogUser AS MaNguoiNhap,
        CASE WHEN c.LogUser = N'0044' THEN @TenNguoiNhapMigration ELSE c.LogUser END AS TenNguoiNhap,
        c.LogDateLast AS NgayChinhSuaCuoiCung, c.LogUserLast AS MaNguoiChinhSua,
        CASE WHEN c.LogUserLast = N'0044' THEN @TenNguoiNhapMigration ELSE c.LogUserLast END AS TenNguoiChinhSua,
        ROW_NUMBER() OVER (PARTITION BY tb.NhomThietBiId, c.MaThongSo ORDER BY COALESCE(c.LogDateLast, c.LogDate) DESC, c.IdChiTiet DESC) AS rn
    FROM #ThongSoCu c
    INNER JOIN dbo.ThietBi tb ON tb.MaThietBi = c.MaThietBi
    LEFT JOIN dbo.DmDungChung dvt ON dvt.NhomDanhMuc = N'DON_VI_TINH' AND dvt.Ten = c.TenDonViTinh
), DmSource AS (
    SELECT * FROM DmSourceRaw WHERE rn = 1
)
MERGE dbo.DmThongSoThietBi AS target
USING DmSource AS source
ON target.NhomThietBiId = source.NhomThietBiId AND target.MaThongSo = source.MaThongSo
WHEN MATCHED THEN UPDATE SET
    TenThongSo = source.TenThongSo, KieuDuLieu = N'NUMBER', DonViTinhId = source.DonViTinhId,
    GhiChu = source.GhiChu, IsActive = 1, NgayChinhSuaCuoiCung = source.NgayChinhSuaCuoiCung,
    MaNguoiChinhSua = source.MaNguoiChinhSua, TenNguoiChinhSua = source.TenNguoiChinhSua
WHEN NOT MATCHED BY TARGET THEN
    INSERT (Id, NhomThietBiId, MaThongSo, TenThongSo, KieuDuLieu, DonViTinhId, BatBuoc, SapXep, GhiChu, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap, NgayChinhSuaCuoiCung, MaNguoiChinhSua, TenNguoiChinhSua)
    VALUES (NEWID(), source.NhomThietBiId, source.MaThongSo, source.TenThongSo, N'NUMBER', source.DonViTinhId, 0, TRY_CONVERT(INT, source.MaThongSo), source.GhiChu, 1, source.NgayKhoiTao, source.MaNguoiNhap, source.TenNguoiNhap, source.NgayChinhSuaCuoiCung, source.MaNguoiChinhSua, source.TenNguoiChinhSua);

;WITH ValueSourceRaw AS (
    SELECT
        tb.Id AS ThietBiId, ts.Id AS ThongSoId, c.GiaTriNumber,
        CASE WHEN c.GhiChu IS NULL AND c.IdHstb IS NULL THEN NULL ELSE CONCAT(COALESCE(c.GhiChu, N''), CASE WHEN c.GhiChu IS NOT NULL AND c.IdHstb IS NOT NULL THEN N'; ' ELSE N'' END, CASE WHEN c.IdHstb IS NOT NULL THEN CONCAT(N'Old ID_HSTB: ', c.IdHstb) ELSE N'' END) END AS GhiChu,
        ISNULL(c.LogDate, SYSDATETIME()) AS NgayKhoiTao, c.LogUser AS MaNguoiNhap,
        CASE WHEN c.LogUser = N'0044' THEN @TenNguoiNhapMigration ELSE c.LogUser END AS TenNguoiNhap,
        ROW_NUMBER() OVER (PARTITION BY tb.Id, ts.Id ORDER BY COALESCE(c.LogDateLast, c.LogDate) DESC, c.IdChiTiet DESC) AS rn
    FROM #ThongSoCu c
    INNER JOIN dbo.ThietBi tb ON tb.MaThietBi = c.MaThietBi
    INNER JOIN dbo.DmThongSoThietBi ts ON ts.NhomThietBiId = tb.NhomThietBiId AND ts.MaThongSo = c.MaThongSo
), ValueSource AS (
    SELECT * FROM ValueSourceRaw WHERE rn = 1
)
MERGE dbo.ThietBiThongSo AS target
USING ValueSource AS source
ON target.ThietBiId = source.ThietBiId AND target.ThongSoId = source.ThongSoId
WHEN MATCHED THEN UPDATE SET
    GiaTriText = NULL, GiaTriNumber = source.GiaTriNumber, GiaTriDate = NULL, GiaTriBit = NULL, GhiChu = source.GhiChu,
    NgayKhoiTao = source.NgayKhoiTao, MaNguoiNhap = source.MaNguoiNhap, TenNguoiNhap = source.TenNguoiNhap
WHEN NOT MATCHED BY TARGET THEN
    INSERT (Id, ThietBiId, ThongSoId, GiaTriText, GiaTriNumber, GiaTriDate, GiaTriBit, GhiChu, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.ThietBiId, source.ThongSoId, NULL, source.GiaTriNumber, NULL, NULL, source.GhiChu, source.NgayKhoiTao, source.MaNguoiNhap, source.TenNguoiNhap);

SELECT
    SourceRows = (SELECT COUNT(*) FROM #ThongSoCu),
    SourceMissingDevice = (SELECT COUNT(*) FROM #ThongSoCu c WHERE NOT EXISTS (SELECT 1 FROM dbo.ThietBi tb WHERE tb.MaThietBi = c.MaThietBi)),
    SourceDuplicateDeviceParameter = (SELECT COUNT(*) FROM (SELECT MaThietBi, MaThongSo FROM #ThongSoCu GROUP BY MaThietBi, MaThongSo HAVING COUNT(*) > 1) d),
    ImportedParameterDefinitions = (SELECT COUNT(*) FROM dbo.DmThongSoThietBi),
    ImportedDeviceParameterValues = (SELECT COUNT(*) FROM dbo.ThietBiThongSo);

COMMIT TRANSACTION;
